struct Point {
	double x, y;
};

__device__ double distanceBetweenPoints(Point const& p1, Point const& p2) {
	return sqrt(pow(p2.x-p1.x, 2) + pow(p2.y-p1.y, 2));
}

/* Compute the distance between the closest two points in the vector points.
